import { describe, it, expect } from "vitest";
import { nextGeneration } from "./game-of-life.js";

describe("Game of Life - nextGeneration", () => {
  it.todo("should return empty array for empty input");
  it.todo("should kill a single live cell (underpopulation)");
  it.todo("should kill two adjacent cells (each has only 1 neighbor)");
  it.todo("should keep a 2x2 block unchanged (still life)");
  it.todo("should transform vertical blinker into horizontal blinker");
  it.todo("should kill a live cell with 4 live neighbors (overpopulation)");
  it.todo("should bring a dead cell with exactly 3 live neighbors to life (reproduction)");
  it.todo("should handle cells with negative coordinates");
});
